// Limpiar el texto: quitar menciones @Miles y @Claude al inicio/final
const rawText = $('Extract Event Data').item.json.message_text || '';
const text = rawText
  .replace(/<@[A-Z0-9]+\|[^>]+>/g, '')  // quitar <@U123|nombre>
  .replace(/<@[A-Z0-9]+>/g, '')          // quitar <@U123>
  .replace(/\*Sent using\*[^\n]*/g, '')  // quitar firma "Sent using @Claude"
  .replace(/Sent using[^\n]*/g, '')       // variante sin asteriscos
  .replace(/\*Enviado usando\*[^\n]*/g, '') // quitar firma en español
  .replace(/Enviado usando[^\n]*/g, '')     // variante sin asteriscos
  .trim();

const channel_id = $('Extract Event Data').item.json.channel_id || '';
const thread_ts  = $('Extract Event Data').item.json.thread_ts  || '';

// Canal → área
const channelMap = {
  'C0AJ2599DA6': 'Finance & Accounting',
  'C0AJ67HK0ES': 'Legal & Compliance',
  'C0AK2PW5BGQ': 'Operations',
  'C0AKNPCNNSU': 'Sales & Partnerships',
  'C0AJMRFP0TD': 'Trading Desk',
  'C0ARDGP8134': 'Management'
};
const area = channelMap[channel_id] || '';

// Parser: soporta formato nuevo (bloques con emoji) y viejo (bullets _Label:_)
const extractBlock = (emojiLabel, bulletLabel) => {
  const blockRegex = new RegExp(
    emojiLabel.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') +
    '\\s*\\n([\\s\\S]*?)(?=\\n[🔍🧭⚠️✅🚨📎👤]|\\n\\n[A-Z🔍🧭⚠️✅🚨📎👤]|$)',
    'i'
  );
  const blockMatch = text.match(blockRegex);
  if (blockMatch && blockMatch[1].trim()) return blockMatch[1].trim();

  const bulletRegex = new RegExp(
    '(?:•\\s*_?' + bulletLabel.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + ':?_?\\*?|\\*' +
    bulletLabel.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + ':\\*)\\s*([^\\n]+)',
    'i'
  );
  const bulletMatch = text.match(bulletRegex);
  return bulletMatch ? bulletMatch[1].trim() : '';
};

const solicitante = extractBlock('👤 Solicitante',       'Solicitante');
const problema    = extractBlock('🔍 Problema',          'Problema');
const contexto    = extractBlock('🧭 Contexto',          'Contexto');
const impacto     = extractBlock('⚠️ Impacto',           'Impacto');
const resultado   = extractBlock('✅ Resultado esperado','Resultado esperado');
const urgencia    = extractBlock('🚨 Urgencia',          'Urgencia');

const problemaFull = problema + (contexto ? '\n\nContexto: ' + contexto : '');

const prioMap = { 'crítico': '1', 'critico': '1', 'alto': '2', 'normal': '3', 'bajo': '4' };
const priority_id = prioMap[(urgencia || '').toLowerCase().trim()] || '3';

const areaIdMap = {
  'Finance & Accounting': '10020',
  'Legal & Compliance':   '10021',
  'Operations':           '10022',
  'Sales & Partnerships': '10023',
  'Trading Desk':         '10024',
  'Management':           '10095'
};
const business_area_id = areaIdMap[area] || '';

const thread_url = 'https://arduasolutions.slack.com/archives/' + channel_id + '/p' + thread_ts.replace('.', '');
const jira_summary = '[Miles] ' + (area ? area + ' — ' : '') + problemaFull.replace(/\n/g, ' ').substring(0, 120);

return [{ json: {
  channel_id,
  thread_ts,
  area,
  solicitante,
  captured_area:      area,
  captured_problema:  problemaFull,
  captured_impacto:   impacto,
  captured_resultado: resultado,
  captured_urgencia:  urgencia,
  priority_id,
  business_area_id,
  thread_url,
  jira_summary
}}];

const msg = ($('Extract Event Data').item.json.message_text || '').toLowerCase().trim();

const channelMap = {
  'C0AJ2599DA6': 'Finance & Accounting',
  'C0AJ67HK0ES': 'Legal & Compliance',
  'C0AK2PW5BGQ': 'Operations',
  'C0AKNPCNNSU': 'Sales & Partnerships',
  'C0AJMRFP0TD': 'Trading Desk',
  'C0ARDGP8134': 'Management'
};
const channelId = $('Extract Event Data').item.json.channel_id || '';
const area = channelMap[channelId] || '';

// === FAST PATH: Confirmation detection ===
const threadMessages = (() => {
  try { return $('Fetch Thread History').item.json.messages || []; }
  catch(e) { return []; }
})();

const botMessages = threadMessages.filter(m => m.bot_id);
const lastBotMsg = botMessages.length > 0 ? botMessages[botMessages.length - 1] : null;
const isConfirmationPending = lastBotMsg &&
  (lastBotMsg.text || '').includes('este requerimiento');
const isAffirmative = /^(s[ií]|ok|dale|confirmo|correcto|listo|yes|sip|sep|afirmativo|claro)\s*[.!?,]*\s*$/i.test(msg);

if (isConfirmationPending && isAffirmative) {
  const summaryText = lastBotMsg.text || '';
  const extract = (label) => {
    const re = new RegExp('[•\\-]\\s*' + label + ':\\s*(.+)', 'i');
    const m = summaryText.match(re);
    return m ? m[1].trim() : '';
  };

  return [{ json: {
    ...$input.item.json,
    fast_intent: 'req-confirm',
    fast_issue_key: '',
    fast_area: area,
    confirm_area: extract('Área') || extract('Area'),
    confirm_problema: extract('Problema'),
    confirm_impacto: extract('Impacto'),
    confirm_resultado: extract('Resultado esperado'),
    confirm_urgencia: extract('Urgencia')
  }}];
}

// === FAST PATH: req-status ===
const reqMatch = msg.match(/\breq-(\d+)\b/i);
if (reqMatch) {
  return [{ json: { ...$input.item.json, fast_intent: 'req-status', fast_issue_key: 'REQ-' + reqMatch[1], fast_area: area } }];
}

// === FAST PATH: req-list ===
if (/\b(ver|listar|mostrar|listado)\b/.test(msg) || /mis requerimientos|requerimientos del.rea|qu[eé] tickets|cu[aá]les son/.test(msg)) {
  return [{ json: { ...$input.item.json, fast_intent: 'req-list', fast_issue_key: '', fast_area: area } }];
}

return [{ json: { ...$input.item.json, fast_intent: '', fast_issue_key: '', fast_area: area } }];

const isClaude = (() => {
  try { return $('Parse Claude Message').item !== undefined; } catch(e) { return false; }
})();

let bp, pr;

if (isClaude) {
  pr = $('Parse Claude Message').first().json;
  bp = {
    jira_summary:     pr.jira_summary,
    business_area_id: pr.business_area_id,
    priority_id:      pr.priority_id,
    thread_url:       pr.thread_url
  };
} else {
  bp = $('Build Jira Payload').first().json;
  pr = $('Parse AI Response').first().json;
}

const clean = (s) => (s || '').replace(/\n/g, ' ').replace(/\r/g, '').replace(/\t/g, ' ').trim() || '-';

const desc = {
  type: 'doc', version: 1,
  content: [
    { type: 'paragraph', content: [{ type: 'text', text: 'Capturado por Miles via Slack', marks: [{ type: 'em' }] }] },
    { type: 'paragraph', content: [{ type: 'text', text: '🔗 Ver hilo en Slack', marks: [{ type: 'link', attrs: { href: bp.thread_url } }] }] },
    { type: 'rule' },
    { type: 'heading', attrs: { level: 3 }, content: [{ type: 'text', text: 'Problema' }] },
    { type: 'paragraph', content: [{ type: 'text', text: clean(pr.captured_problema) }] },
    { type: 'heading', attrs: { level: 3 }, content: [{ type: 'text', text: 'Impacto' }] },
    { type: 'paragraph', content: [{ type: 'text', text: clean(pr.captured_impacto) }] },
    { type: 'heading', attrs: { level: 3 }, content: [{ type: 'text', text: 'Resultado esperado' }] },
    { type: 'paragraph', content: [{ type: 'text', text: clean(pr.captured_resultado) }] },
    { type: 'rule' },
    { type: 'paragraph', content: [{ type: 'text', text: 'Urgencia: ' + clean(pr.captured_urgencia) }] }
  ]
};

const fields = {
  project:    { key: 'REQ' },
  issuetype:  { name: 'Requirement' },
  summary:    bp.jira_summary,
  priority:   { id: bp.priority_id || '3' },
  customfield_10171: { id: '10026' },
  description: desc
};

if (bp.business_area_id) {
  fields.customfield_10170 = { id: bp.business_area_id };
}

return [{ json: { jira_body: JSON.stringify({ fields }) } }];

// IDEMPOTENCIA: Si Miles ya respondió en este hilo, ignorar el evento (deduplicación de Slack retries)
const msgs = ($json.messages || []);
const thread_ts = $('Extract Event Data').item.json.thread_ts;

// Buscar cualquier mensaje de bot (Miles) que NO sea el mensaje padre
const milesAlreadyReplied = msgs.some(m => 
  m.bot_id &&        // es mensaje de bot (Miles)
  m.ts !== thread_ts // no es el mensaje padre original
);

return [{ json: { ...$json, is_duplicate: milesAlreadyReplied } }];

